prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?reachable ?reachableName ?type WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-C4E26F66-018C-4395-BD12-4992568F7C4C> ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachableName . }
  OPTIONAL { ?reachable a ?type . }
  FILTER(CONTAINS(LCASE(STR(?reachableName)), LCASE("Opis resenja problema")) || STR(?reachable) = "https://www.teamingai-project.eu/kg/process/qualityInspection/sid-40F7A45F-D611-403F-887D-2B6A3CADD93B")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?direction ?type WHERE {
  ?gateway a ?type .
  FILTER(?type IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_edab148c_8f79_4e08_b9b1_b11f3b1a0c1f> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?nextNode ?nextName ?type WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-59961FB6-4733-4F3E-88C7-A469AAFB0734> .
  ?edge bbo:has_targetRef ?nextNode .
  OPTIONAL { ?nextNode bbo:name ?nextName . }
  OPTIONAL { ?nextNode a ?type . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?reachable ?reachableName ?type WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-CECDE610-E982-4FAA-9FC9-CA39353360D2> ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachableName . }
